import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input received from a form or any other source
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input with HTML encoding to prevent XSS
        String sanitizedInput = Encode.forHtml(userInput);
        String output = "Welcome, " + sanitizedInput;

        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println(output);
            out.close();
            System.out.println("Output has been written to output.html file.");
        } catch (IOException e) {
            System.out.println("An error occurred while writing output.");
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
